<head></head>
<body>
<div class="javascript_css"></div>
<script>
function functionName() { var divElement = document.createElement("div");
divElement.setAttribute("id", "div0");
divElement.setAttribute("class", "div_simple");
divElement.style.position = "absolute";
divElement.style.top = "60px";
divElement.style.width = "300px";
divElement.style.height = "300px";
divElement.style.border = "1px solid gray";
divElement.style.borderRadius = "5px";
document.getElementsByClassName("javascript_css")[0].appendChild(divElement);
var pElement = document.createElement("p");
pElement.setAttribute("id", "p_0");
pElement.setAttribute("class", "p_simple");
pElement.setAttribute("onclick", "processEvent_click(event)");
pElement.style.position = "absolute";
pElement.style.top = "150px";
pElement.style.left = "80px";
pElement.style.width = "40px";
pElement.style.height = "40px";
pElement.style.transition = "all 0.5s ease-out";
pElement.style.transform = "rotateY(180deg)";
pElement.style.fontSize = "50px";
pElement.style.zIndex = "10";
pElement.innerText = "🦖";
document.getElementById("div0").appendChild(pElement);
var pElement = document.createElement("p");
pElement.setAttribute("id", "p_1");
pElement.setAttribute("class", "p_simple");
pElement.style.position = "absolute";
pElement.style.top = "160px";
pElement.style.left = "5px";
pElement.style.width = "40px";
pElement.style.height = "40px";
pElement.style.fontSize = "50px";
pElement.style.color = "gray";
pElement.style.zIndex = "0";
pElement.innerText = "_____________";
document.getElementById("div0").appendChild(pElement);
var pElement = document.createElement("p");
pElement.setAttribute("id", "p_2");
pElement.setAttribute("class", "p_simple");
pElement.style.position = "absolute";
pElement.style.top = "150px";
pElement.style.left = "240px";
pElement.style.width = "40px";
pElement.style.height = "40px";
pElement.style.transition = "all 0.5s ease-out";
pElement.style.fontSize = "50px";
pElement.style.zIndex = "0";
pElement.innerText = "🌵︎";
document.getElementById("div0").appendChild(pElement);
var pElement = document.createElement("p");
pElement.setAttribute("id", "p1");
pElement.setAttribute("class", "p_simple");
pElement.style.position = "absolute";
pElement.style.top = "370px";
pElement.style.width = "300px";
pElement.style.height = "100px";
pElement.style.border = "1px solid gray";
pElement.style.borderRadius = "5px";
pElement.style.backgroundColor = "hsl(60 100% 90%)";
pElement.style.overflow = "scroll";
document.getElementsByClassName("javascript_css")[0].appendChild(pElement);
keyframes_javascript2(document.getElementById("p_2"));
}
async function processEvent_click(event) {
var top = ["30px", "150px"];
await motion(top.at(0));
await setTimeout(async () => { await motion(top.at(1)); }, 500);
}
async function motion(top) {
var num = parseInt(document.getElementById("p_0").id.split("p_").at(1));
// document.getElementById("p1").innerHTML += "num: "+num+"<br>";
var current = `${document.getElementById("p_0").style.top}`;
document.getElementById("p1").innerHTML += "current: "+current+"<br>";
var next = top;
debounce1(keyframes([num, current, next]), 200);
}
</script>
<script>
function keyframes_javascript2(event_target) {
const keyframes = [
{ transform: "translate(20px)" },
{ transform: "translate(-240px)" },
];
const timing = {
duration: 2000,
iterations: "Infinity",
};
event_target.animate(keyframes, timing);
}
</script>
<script>
function keyframes([num, current, next]) {
var iterations = 10;
var current_arr = current.split("px").map((v,i) => { return parseInt(v.trim()); }).slice(0,1);
document.getElementById("p1").innerHTML += "current_arr: "+current_arr+"<br>";
var next_arr = next.split("px").map((v,i) => { return parseInt(v.trim()); }).slice(0,1);
document.getElementById("p1").innerHTML += "next_arr: "+next_arr+"<br>";
var increment = next_arr.map((v,i) => { return Math.abs((v-current_arr.at(i))/iterations); });
document.getElementById("p1").innerHTML += "increment: "+increment+"<br>";
var top = current_arr.at(0);
for (var i=0; i<iterations; i++) {
if (top < next_arr.at(0)) { top = top+increment.at(0); } else { top = top-increment.at(0); }
// document.getElementById("p1").innerHTML += "top: "+top+"<br>";
document.getElementById("p_"+num).style.top = `${top}px`;
}
}
function debounce1(functionName, delay) {
var timeout = null;
return (...args) => {
clearTimeout(timeout);
timeout = setTimeout(() => { functionName(...args); }, delay);
}
}
</script>
<script>
topbar();
function topbar() {
document.getElementsByClassName("javascript_css")[0].style.position = "absolute";
document.getElementsByClassName("javascript_css")[0].style.width = "300px";
document.getElementsByClassName("javascript_css")[0].style.height = "50px";
document.getElementsByClassName("javascript_css")[0].style.border = "1px solid gray";
document.getElementsByClassName("javascript_css")[0].style.borderRadius = "2px";
document.getElementsByClassName("javascript_css")[0].style.fontSize = "12px";
document.getElementsByClassName("javascript_css")[0].innerHTML = "Dinosaur Run. Inspired by Chrome Dino Run. Click-on the t-rex to make it jump over the cactus.";
functionName();
}
</script>
</body>
</html>
